// Evaluate Outcomes 芒聙聰 v6 (triple-barrier + Wilson lower bound)
const https = require('https');

// Fetch current price
const currentPrice = await new Promise((resolve) => {
  const req = https.get('https://api.kraken.com/0/public/Ticker?pair=XETHZUSD', (res) => {
    let d = '';
    res.on('data', c => d += c);
    res.on('end', () => {
      try {
        const j = JSON.parse(d);
        const key = Object.keys(j.result || {})[0];
        resolve(key ? parseFloat(j.result[key].c[0]) : 0);
      } catch(e) { resolve(0); }
    });
  });
  req.on('error', () => resolve(0));
  req.setTimeout(8000, () => { req.destroy(); resolve(0); });
});

if (currentPrice === 0) {
  return [{ json: { error: 'No ETH price', hitRate: 0, evaluated: 0, summary: 'OUTCOME ERROR: ETH price unavailable', adaptiveParams: null, telegramMsg: '\u26A0 OUTCOME TRACKER ERROR: ETH price fetch failed.' } }];
}

const vaultRaw = $input.first().json;
const memories = (vaultRaw && vaultRaw.memories) ? vaultRaw.memories : [];
const cutoff48h = new Date(Date.now() - 48 * 3600 * 1000).toISOString();

let correct = 0, incorrect = 0, neutral = 0, tooSoon = 0, stale = 0;
const outcomes = [];

// Wilson lower bound (z=1.96 for 95% CI)
const wilsonLower = (wins, n, z = 1.96) => {
  if (n === 0) return 0;
  const p = wins / n;
  const denom = 1 + (z*z)/n;
  const center = (p + (z*z)/(2*n)) / denom;
  const margin = (z/denom) * Math.sqrt((p*(1-p))/n + (z*z)/(4*n*n));
  return Math.max(0, center - margin);
};

for (const mem of memories) {
  const content = mem.content || '';
  const createdAt = mem.created_at || '';
  if (createdAt && createdAt < cutoff48h) { stale++; continue; }
  if (!content.includes('TRADE SIGNAL')) continue;
  const dirMatch   = content.match(/\\b(BUY|SELL|WAIT)\\s+ETH\\b/);
  const priceMatch = content.match(/@ \$([\d,]+(?:\.\d+)?)/);
  const confMatch  = content.match(/Confidence:([\d.]+)%/);
  const regMatch   = content.match(/Regime:(\w+)/);
  const atrMatch   = content.match(/ATR\(?14\)?:?\s*\$?([\d.]+)/);
  if (!dirMatch || !priceMatch) continue;
  const dir = dirMatch[1];
  const regime = regMatch ? regMatch[1] : 'UNKNOWN';
  const signalPrice = parseFloat(priceMatch[1].replace(/,/g, ''));
  const conf = confMatch ? parseFloat(confMatch[1]) : 50;
  const atr14 = atrMatch ? parseFloat(atrMatch[1]) : signalPrice * 0.015; // fallback 1.5%
  if (dir === 'WAIT') { neutral++; continue; }
  if (signalPrice === 0) continue;
  const ageSecs = createdAt ? (Date.now() - new Date(createdAt).getTime()) / 1000 : 14400;

  // 芒聰聙芒聰聙芒聰聙 TRIPLE-BARRIER GRADING 芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙
  // TP barrier: signal direction 脙聴 1.5脙聴ATR profit
  // SL barrier: signal direction 脙聴 1.0脙聴ATR loss
  // Time barrier: 4h after signal (the OT cycle)
  // Without intra-period prices we use current price + age as proxy:
  //   - if pctMove crossed +1.5脙聴ATR/price magnitude 芒聠聮 TP hit (CORRECT for BUY)
  //   - if pctMove crossed -1.0脙聴ATR/price 芒聠聮 SL hit (INCORRECT for BUY)
  //   - if neither 芒聠聮 time hit, label by sign of move (with min threshold)
  const tpThreshold = (1.5 * atr14 / signalPrice) * 100; // % move for TP
  const slThreshold = (1.0 * atr14 / signalPrice) * 100; // % move for SL
  const minMove = ageSecs < 3600 ? 0.3 : ageSecs < 14400 ? 0.6 : 1.2;
  const pctMove = ((currentPrice - signalPrice) / signalPrice) * 100;
  const dirMove = dir === 'BUY' ? pctMove : -pctMove; // signed move in signal direction

  let outcome, hitType;
  if (dirMove >= tpThreshold)        { outcome = 'CORRECT';   hitType = 'TP'; correct++; }
  else if (dirMove <= -slThreshold)  { outcome = 'INCORRECT'; hitType = 'SL'; incorrect++; }
  else if (Math.abs(pctMove) < minMove) { outcome = 'TOO_SOON'; hitType = 'EARLY'; tooSoon++; }
  else if (dirMove > 0)              { outcome = 'CORRECT';   hitType = 'TIME'; correct++; }
  else                                { outcome = 'INCORRECT'; hitType = 'TIME'; incorrect++; }

  outcomes.push({ dir, regime, signalPrice, currentPrice: Math.round(currentPrice), pctMove: Math.round(pctMove*100)/100, conf, outcome, hitType, ageMins: Math.round(ageSecs/60), ageSecs, tpThreshold: tpThreshold.toFixed(2), slThreshold: slThreshold.toFixed(2) });
}

const gradeable    = correct + incorrect;
const hitRateRaw   = gradeable > 0 ? Math.round((correct / gradeable) * 100) : 0;
const hitRateWilson = Math.round(wilsonLower(correct, gradeable) * 100); // pessimistic estimate
const graded       = outcomes.filter(o => o.outcome !== 'TOO_SOON');
const avgConf      = graded.length > 0 ? Math.round(graded.reduce((s, o) => s + o.conf, 0) / graded.length * 10) / 10 : 0;
const evaluated    = correct + incorrect + neutral + tooSoon;
const recentGraded = graded.slice(0, 3);
const dataQuality  = gradeable < 5 ? 'INSUFFICIENT' : gradeable < 10 ? 'BUILDING' : 'SUFFICIENT';
const threshold    = 55;

// Per-direction with Wilson lower
const buyGraded  = graded.filter(o => o.dir === 'BUY');
const sellGraded = graded.filter(o => o.dir === 'SELL');
const buyCorrect  = buyGraded.filter(o  => o.outcome === 'CORRECT').length;
const sellCorrect = sellGraded.filter(o => o.outcome === 'CORRECT').length;
const buyHitRate  = buyGraded.length  > 0 ? Math.round(buyCorrect / buyGraded.length * 100) : 50;
const sellHitRate = sellGraded.length > 0 ? Math.round(sellCorrect / sellGraded.length * 100) : 50;
const buyHRWilson  = Math.round(wilsonLower(buyCorrect, buyGraded.length) * 100);
const sellHRWilson = Math.round(wilsonLower(sellCorrect, sellGraded.length) * 100);

// Per-regime accuracy with exponential time-decay (36h half-life)
const regimeStats = {};
for (const o of graded) {
  const r = o.regime || 'UNKNOWN';
  if (!regimeStats[r]) regimeStats[r] = { correct: 0, total: 0, weightedCorrect: 0, weightedTotal: 0 };
  const ageHours = (o.ageSecs || 14400) / 3600;
  const decayW = Math.exp(-ageHours / 36);
  regimeStats[r].total++;
  regimeStats[r].weightedTotal += decayW;
  if (o.outcome === 'CORRECT') {
    regimeStats[r].correct++;
    regimeStats[r].weightedCorrect += decayW;
  }
}

// Confidence calibration
const highConfGraded = graded.filter(o => o.conf >= 75);
const lowConfGraded  = graded.filter(o => o.conf < 65);
const highConfHR = highConfGraded.length >= 3 ? Math.round(highConfGraded.filter(o => o.outcome === 'CORRECT').length / highConfGraded.length * 100) : hitRateRaw;
const lowConfHR  = lowConfGraded.length  >= 3 ? Math.round(lowConfGraded.filter(o  => o.outcome === 'CORRECT').length / lowConfGraded.length  * 100) : hitRateRaw;
const confCalibrated = highConfHR < lowConfHR - 10;

// 芒聰聙芒聰聙芒聰聙 Brier score (calibration metric) 芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙芒聰聙
const brierPairs = graded.map(o => ({ prob: o.conf / 100, outcome: o.outcome === 'CORRECT' ? 1 : 0 }));
const brier = brierPairs.length > 0 ? brierPairs.reduce((s, p) => s + (p.prob - p.outcome) ** 2, 0) / brierPairs.length : null;
const brierGrade = brier === null ? 'N/A' : brier < 0.18 ? 'EXCELLENT' : brier < 0.22 ? 'GOOD' : brier < 0.25 ? 'MARGINAL' : 'POOR';

// Adaptive minConf 芒聙聰 driven by WILSON LOWER, not raw hitRate
let adaptiveMinConf = 60;
if (gradeable >= 10) {
  if      (hitRateWilson < 35)  adaptiveMinConf = 68;
  else if (hitRateWilson < 42)  adaptiveMinConf = 65;
  else if (hitRateWilson < 50)  adaptiveMinConf = 62;
  else if (hitRateWilson > 65 && !confCalibrated) adaptiveMinConf = 56;
  else if (hitRateWilson > 58 && !confCalibrated) adaptiveMinConf = 58;
  else                          adaptiveMinConf = 60;
  if (confCalibrated) adaptiveMinConf = Math.min(adaptiveMinConf + 4, 68);
}

// Direction multipliers 芒聙聰 also driven by Wilson lower
const buyMult  = gradeable >= 8 ? parseFloat(Math.max(0.80, Math.min(1.20, 0.60 + (buyHRWilson  / 100) * 0.6)).toFixed(2)) : 1.0;
const sellMult = gradeable >= 8 ? parseFloat(Math.max(0.80, Math.min(1.20, 0.60 + (sellHRWilson / 100) * 0.6)).toFixed(2)) : 1.0;

// Strategy weight adaptation
const defaultWt = { trend:1.5, meanRev:1.0, momentum:1.2, breakout:1.1, smc:1.3, multiTF:1.8, fibonacci:0.9, macro:1.3, micro:1.3, stat:0.8 };
const regimeToStrat = {
  BULL_TREND_STRONG: ['trend','multiTF','momentum'], BULL_TREND_WEAK: ['trend','multiTF'],
  BEAR_TREND_STRONG: ['trend','multiTF','momentum'], BEAR_TREND_WEAK: ['trend','multiTF'],
  RANGE_BOUND: ['meanRev','smc','fibonacci'], BREAKOUT_BULL: ['breakout','momentum','micro'],
  BREAKOUT_BEAR: ['breakout','momentum','micro'], HIGH_VOL_EXPAND: ['breakout','momentum'],
  LOW_VOL_COMPRESS: ['meanRev','fibonacci'], RISK_ON: ['macro','multiTF'],
  RISK_OFF: ['macro','stat'], EXTREME_CAUTION: ['macro','stat'],
};

const adaptiveWt = Object.assign({}, defaultWt);
if (gradeable >= 10) {
  for (const [regime, stats] of Object.entries(regimeStats)) {
    if (stats.weightedTotal < 1.5) continue;
    const weightedHR = stats.weightedCorrect / stats.weightedTotal;
    const delta = weightedHR > 0.70 ? 0.15 : weightedHR > 0.60 ? 0.08 : weightedHR < 0.35 ? -0.18 : weightedHR < 0.45 ? -0.10 : 0;
    if (delta === 0) continue;
    for (const s of (regimeToStrat[regime] || [])) {
      if (adaptiveWt[s] !== undefined) adaptiveWt[s] = Math.round(Math.max(0.4, Math.min(2.8, adaptiveWt[s] + delta)) * 100) / 100;
    }
  }
  const origSum = Object.values(defaultWt).reduce((a, b) => a + b, 0);
  const newSum  = Object.values(adaptiveWt).reduce((a, b) => a + b, 0);
  if (newSum > 0.1) for (const k of Object.keys(adaptiveWt)) adaptiveWt[k] = Math.round(adaptiveWt[k] / newSum * origSum * 100) / 100;
}

const regimeStatsSummary = Object.fromEntries(
  Object.entries(regimeStats).filter(([, s]) => s.total > 0)
    .map(([r, s]) => [r, s.correct + '/' + s.total + '(' + Math.round(s.weightedCorrect/Math.max(s.weightedTotal,0.01)*100) + '%w)'])
);

const adaptiveParams = 'ETH_ADAPT_PARAMS | ' + new Date().toISOString().slice(0,16) + 'Z'
  + ' | minConf:' + adaptiveMinConf + ' | buyMult:' + buyMult + ' | sellMult:' + sellMult
  + ' | hitRate:' + hitRateRaw + '% | hitRateWilson:' + hitRateWilson + '%'
  + ' | buyHR:' + buyHitRate + '% | sellHR:' + sellHitRate + '%'
  + ' | buyHRWilson:' + buyHRWilson + '% | sellHRWilson:' + sellHRWilson + '%'
  + ' | brier:' + (brier === null ? 'NA' : brier.toFixed(3))
  + ' | highConfHR:' + highConfHR + '% | gradeable:' + gradeable
  + ' | wt:' + JSON.stringify(adaptiveWt) + ' | regimeStats:' + JSON.stringify(regimeStatsSummary)
  + ' | dataQuality:' + dataQuality;

// Hit type breakdown (TP/SL/TIME/EARLY)
const tpHits   = outcomes.filter(o => o.hitType === 'TP').length;
const slHits   = outcomes.filter(o => o.hitType === 'SL').length;
const timeHits = outcomes.filter(o => o.hitType === 'TIME').length;

const summary = 'OUTCOME REPORT | ' + new Date().toISOString().slice(0,16) + 'Z\nETH @ $' + Math.round(currentPrice)
  + '\nEvaluated: ' + evaluated + ' (' + gradeable + ' gradeable, ' + tooSoon + ' too-soon, ' + stale + ' stale, ' + neutral + ' waits)'
  + '\nHit Rate: ' + hitRateRaw + '% raw | ' + hitRateWilson + '% Wilson lower (' + correct + '/' + gradeable + ' graded)'
  + '\nBarriers: TP=' + tpHits + ' SL=' + slHits + ' TIME=' + timeHits
  + '\nBUY accuracy: ' + buyHitRate + '%/' + buyHRWilson + '%w (' + buyGraded.length + ' sigs) | SELL: ' + sellHitRate + '%/' + sellHRWilson + '%w (' + sellGraded.length + ' sigs)'
  + '\nBrier: ' + (brier === null ? 'N/A' : brier.toFixed(3)) + ' (' + brierGrade + ')'
  + '\nAdaptive minConf: ' + adaptiveMinConf + ' | buyMult: ' + buyMult + ' | sellMult: ' + sellMult
  + '\nLast 3 graded: ' + (recentGraded.map(o => o.dir + '[' + o.hitType + '] ' + o.outcome + ' (' + o.pctMove + '%)').join(' | ') || 'none yet');

const ts = new Date().toISOString().replace('T', ' ').slice(0, 16) + ' UTC';
const HR = '\u2501'.repeat(20);
const hrBadge = hitRateWilson >= 60 ? '\uD83D\uDD25' : hitRateWilson >= 50 ? '\u2705' : hitRateWilson > 0 ? '\u26A0' : '\uD83D\uDCCA';
const hrStatus = hitRateWilson >= threshold ? '\u2705 Wilson lower bound above ' + threshold + '%' : hitRateWilson > 0 ? '\u26A0 Wilson below ' + threshold + '% 芒聙聰 paper mode' : '\uD83D\uDCCA Accumulating data';
const dqBadge = dataQuality === 'SUFFICIENT' ? '\uD83D\uDFE2' : dataQuality === 'BUILDING' ? '\uD83D\uDFE1' : '\uD83D\uDD34';
const outcomeLines = recentGraded.map(o => {
  const ico = o.outcome === 'CORRECT' ? '\u2705' : '\u274C';
  const dir2 = o.dir === 'BUY' ? '\uD83D\uDFE2 BUY' : '\uD83D\uDD34 SELL';
  const hit = o.hitType === 'TP' ? '\uD83C\uDFAF TP' : o.hitType === 'SL' ? '\uD83D\uDED1 SL' : '\u23F1 TIME';
  return ico + ' ' + dir2 + ' ' + hit + '  $' + o.signalPrice.toLocaleString('en-US') + '  \u2192  ' + (o.pctMove >= 0 ? '+' : '') + o.pctMove + '%  (' + o.ageMins + 'min)';
});
const adaptLine = gradeable >= 10
  ? '\n\u2699 <b>Adaptive params updated</b>: minConf <b>' + adaptiveMinConf + '</b> | BUY\xd7' + buyMult + ' | SELL\xd7' + sellMult
  : '\n\u23F3 Collecting data for adaptation (' + gradeable + '/10 needed)';

const telegramMsg = [
  '\uD83D\uDCCA <b>PERFORMANCE UPDATE 芒聙聰 ETH v1</b>',
  '\uD83D\uDDD3 ' + ts, '', HR,
  hrBadge + ' <b>HIT RATE: ' + hitRateRaw + '% raw | ' + hitRateWilson + '% Wilson</b> (' + correct + '/' + gradeable + ')',
  hrStatus, HR, '',
  '\uD83D\uDCB0 ETH: <b>$' + Math.round(currentPrice).toLocaleString('en-US') + '</b>',
  '\uD83D\uDCE6 Avg Confidence: <b>' + avgConf + '%</b>   Brier: <b>' + (brier === null ? 'N/A' : brier.toFixed(3)) + '</b> ' + brierGrade,
  '',
  '<b>Outcome breakdown:</b>',
  '\u2705 Correct: <b>' + correct + '</b>   \u274C Incorrect: <b>' + incorrect + '</b>   \u23F3 Too-soon: <b>' + tooSoon + '</b>',
  '\uD83C\uDFAF TP: ' + tpHits + '   \uD83D\uDED1 SL: ' + slHits + '   \u23F1 TIME: ' + timeHits,
  '\u26AA Wait: <b>' + neutral + '</b>   \uD83D\uDCC5 Stale (>48h): <b>' + stale + '</b>',
  '\uD83D\uDFE2 BUY: <b>' + buyHitRate + '%</b>/' + buyHRWilson + '%w (' + buyGraded.length + ')   \uD83D\uDD34 SELL: <b>' + sellHitRate + '%</b>/' + sellHRWilson + '%w (' + sellGraded.length + ')',
  adaptLine, '',
  '<b>Last graded:</b>',
  outcomeLines.length ? outcomeLines.join('\n') : '<i>No graded signals yet</i>',
  '',
  dqBadge + ' Data quality: <b>' + dataQuality + '</b>  (' + gradeable + ' graded)',
  '',
  '<i>\u23F1 Every 4h  \u00B7  Triple-barrier + Wilson lower  \u00B7  v6</i>'
].join('\n');

return [{ json: { summary, hitRate: hitRateRaw, hitRateWilson, correct, incorrect, neutral, tooSoon, stale, evaluated, gradeable, currentPrice, avgConf, outcomes: outcomes.slice(0, 10), dataQuality, buyHitRate, sellHitRate, buyHRWilson, sellHRWilson, adaptiveMinConf, buyMult, sellMult, adaptiveWt, adaptiveParams, confCalibrated, highConfHR, lowConfHR, brier, brierGrade, tpHits, slHits, timeHits, telegramMsg } }];

// Write Outcome Summary to inspiring-cat vault
const https = require('https');
const data = $input.first().json;
const summary = data.summary || 'OUTCOME REPORT: no summary';

const payload = JSON.stringify({
  memories: [{
    content: summary,
    source: 'outcome_tracker',
    memory_type: 'episodic',
    importance: 4,
    tags: ['eth_outcome', 'performance']
  }]
});

const result = await new Promise((resolve) => {
  const opts = {
    hostname: 'inspiring-cat-production.up.railway.app',
    path: '/memory/ingest',
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'X-Memory-Secret': '2dc6c69574c14d615ce146e54640aa13030dade7aa86697c',
      'Content-Length': Buffer.byteLength(payload)
    }
  };
  const req = https.request(opts, (res) => {
    let d = '';
    res.on('data', c => d += c);
    res.on('end', () => { try { resolve(JSON.parse(d)); } catch(e) { resolve({ ok: false, err: d.slice(0,80) }); } });
  });
  req.on('error', e => resolve({ ok: false, err: e.message }));
  req.setTimeout(8000, () => { req.destroy(); resolve({ ok: false, err: 'timeout' }); });
  req.write(payload);
  req.end();
});

return [{ json: { stored: !!result.ok, result, summary: summary.slice(0, 100) } }];

// Write Adaptive Params to inspiring-cat vault
const https = require('https');
const data = $input.first().json;
const adaptiveParams = data.adaptiveParams;

if (!adaptiveParams) {
  return [{ json: { stored: false, reason: 'no adaptiveParams in input 芒聙聰 data quality insufficient' } }];
}

const payload = JSON.stringify({
  memories: [{
    content: adaptiveParams,
    source: 'eth_outcome_tracker',
    memory_type: 'adaptive',
    importance: 5,
    tags: ['eth_adapt_params', 'performance', 'learning']
  }]
});

const result = await new Promise((resolve) => {
  const opts = {
    hostname: 'inspiring-cat-production.up.railway.app',
    path: '/memory/ingest',
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'X-Memory-Secret': '2dc6c69574c14d615ce146e54640aa13030dade7aa86697c',
      'Content-Length': Buffer.byteLength(payload)
    }
  };
  const req = https.request(opts, (res) => {
    let d = '';
    res.on('data', c => d += c);
    res.on('end', () => { try { resolve(JSON.parse(d)); } catch(e) { resolve({ ok: false, err: d.slice(0,80) }); } });
  });
  req.on('error', e => resolve({ ok: false, err: e.message }));
  req.setTimeout(8000, () => { req.destroy(); resolve({ ok: false, err: 'timeout' }); });
  req.write(payload);
  req.end();
});

return [{ json: { stored: !!result.ok, result, adaptiveParams: adaptiveParams.slice(0, 150) } }];
